QUESTIONS = [
    { "id":1,  "theme":"Organisational", "control":"A.5.1",  "weight":3, "text":"Does your organisation have a documented information security policy approved by management?", "remediation":"Draft and approve a formal information security policy signed by senior management." },
    { "id":2,  "theme":"Organisational", "control":"A.5.2",  "weight":3, "text":"Are information security roles and responsibilities clearly defined and assigned?", "remediation":"Define and document security roles and responsibilities for all relevant staff." },
    { "id":3,  "theme":"Organisational", "control":"A.5.10", "weight":2, "text":"Do you have acceptable use rules for information and IT assets?", "remediation":"Create an acceptable use policy covering devices, email, internet, and data handling." },
    { "id":4,  "theme":"Organisational", "control":"A.5.24", "weight":3, "text":"Do you have a documented incident response plan?", "remediation":"Develop and test a formal incident response plan covering detection, containment, and recovery." },
    { "id":5,  "theme":"Organisational", "control":"A.5.26", "weight":3, "text":"Do you have a process to respond to and report information security incidents?", "remediation":"Establish a clear incident reporting process including escalation paths and response timelines." },
    { "id":6,  "theme":"Organisational", "control":"A.5.29", "weight":2, "text":"Do you have a business continuity plan for information security disruptions?", "remediation":"Develop a business continuity plan that addresses information security during disruptions." },
    { "id":7,  "theme":"Organisational", "control":"A.5.31", "weight":2, "text":"Has your organisation identified all legal and regulatory requirements related to information security?", "remediation":"Conduct a legal and regulatory review to identify all applicable compliance requirements." },
    { "id":8,  "theme":"Organisational", "control":"A.5.32", "weight":1, "text":"Do you have a process for protecting intellectual property rights?", "remediation":"Implement controls to protect intellectual property including software licensing compliance." },
    { "id":9,  "theme":"Organisational", "control":"A.5.33", "weight":2, "text":"Are your records protected from loss, destruction, and unauthorised access?", "remediation":"Implement record retention policies with appropriate access controls and backup procedures." },
    { "id":10, "theme":"Organisational", "control":"A.5.34", "weight":2, "text":"Do you have a privacy policy and procedures for protecting personal data?", "remediation":"Develop a privacy policy aligned with applicable data protection regulations." },
    { "id":11, "theme":"Organisational", "control":"A.5.36", "weight":2, "text":"Do you regularly review compliance with your information security policies?", "remediation":"Schedule periodic internal reviews or audits of information security policy compliance." },
    { "id":12, "theme":"Organisational", "control":"A.5.37", "weight":1, "text":"Are documented operating procedures available to all staff who need them?", "remediation":"Document key operational procedures and make them accessible to relevant personnel." },
    { "id":13, "theme":"Organisational", "control":"A.5.5",  "weight":2, "text":"Do you have a process for contacting relevant authorities in the event of an incident?", "remediation":"Identify and document contact details for relevant authorities including law enforcement and regulators." },
    { "id":14, "theme":"Organisational", "control":"A.5.6",  "weight":1, "text":"Do you maintain contact with special interest groups or security forums?", "remediation":"Join relevant industry security groups or forums to stay informed of emerging threats." },
    { "id":15, "theme":"Organisational", "control":"A.5.7",  "weight":2, "text":"Do you collect and analyse threat intelligence relevant to your organisation?", "remediation":"Subscribe to threat intelligence feeds and review them regularly for relevant threats." },
    { "id":16, "theme":"People",         "control":"A.6.1",  "weight":2, "text":"Are background checks carried out on new employees before hiring?", "remediation":"Implement a pre-employment screening process including background and reference checks." },
    { "id":17, "theme":"People",         "control":"A.6.2",  "weight":2, "text":"Are information security responsibilities included in employment contracts?", "remediation":"Include information security obligations and confidentiality clauses in all employment contracts." },
    { "id":18, "theme":"People",         "control":"A.6.3",  "weight":3, "text":"Do employees receive regular information security awareness training?", "remediation":"Implement a mandatory annual security awareness training programme for all staff." },
    { "id":19, "theme":"People",         "control":"A.6.5",  "weight":2, "text":"Do employees have defined security responsibilities when leaving the organisation?", "remediation":"Establish an offboarding process that revokes access and retrieves assets upon departure." },
    { "id":20, "theme":"People",         "control":"A.6.7",  "weight":2, "text":"Are remote working security risks managed with appropriate policies and controls?", "remediation":"Implement a remote working policy covering secure access, device management, and data handling." },
    { "id":21, "theme":"Physical",       "control":"A.7.1",  "weight":3, "text":"Are physical entry controls in place to restrict access to secure areas?", "remediation":"Install physical access controls such as key cards, locks, or security guards for sensitive areas." },
    { "id":22, "theme":"Physical",       "control":"A.7.2",  "weight":3, "text":"Are secure areas protected against unauthorised access and environmental threats?", "remediation":"Implement environmental controls including fire suppression, flood protection, and climate control." },
    { "id":23, "theme":"Physical",       "control":"A.7.3",  "weight":2, "text":"Are offices, rooms, and facilities physically secured?", "remediation":"Ensure all offices and facilities have appropriate physical locks and access restrictions." },
    { "id":24, "theme":"Physical",       "control":"A.7.4",  "weight":2, "text":"Do you monitor physical premises for unauthorised access?", "remediation":"Install CCTV or other monitoring systems to detect and record unauthorised physical access." },
    { "id":25, "theme":"Physical",       "control":"A.7.6",  "weight":2, "text":"Are staff aware of and do they follow a clear desk and clear screen policy?", "remediation":"Implement and enforce a clear desk and clear screen policy across the organisation." },
    { "id":26, "theme":"Physical",       "control":"A.7.8",  "weight":2, "text":"Is equipment sited and protected to reduce risks from environmental threats?", "remediation":"Ensure equipment is positioned away from windows and protected from physical damage." },
    { "id":27, "theme":"Physical",       "control":"A.7.9",  "weight":2, "text":"Are assets used outside of premises secured against theft and damage?", "remediation":"Implement controls for off-site assets including encryption and secure transport procedures." },
    { "id":28, "theme":"Physical",       "control":"A.7.14", "weight":2, "text":"Is storage media containing sensitive data securely disposed of when no longer needed?", "remediation":"Implement a secure disposal process for storage media including shredding or certified data wiping." },
    { "id":29, "theme":"Technological",  "control":"A.8.1",  "weight":3, "text":"Do you maintain an inventory of all user endpoints such as laptops and mobile devices?", "remediation":"Create and maintain a complete inventory of all endpoint devices used in the organisation." },
    { "id":30, "theme":"Technological",  "control":"A.8.2",  "weight":3, "text":"Is privileged access to systems and data restricted to authorised users only?", "remediation":"Implement least-privilege access controls and review privileged accounts regularly." },
    { "id":31, "theme":"Technological",  "control":"A.8.3",  "weight":2, "text":"Is access to information and systems restricted based on business need?", "remediation":"Implement role-based access control to ensure users only access what they need." },
    { "id":32, "theme":"Technological",  "control":"A.8.5",  "weight":3, "text":"Is multi-factor authentication used for access to critical systems?", "remediation":"Enable multi-factor authentication on all critical systems and remote access points." },
    { "id":33, "theme":"Technological",  "control":"A.8.6",  "weight":2, "text":"Do you monitor and manage the capacity of systems and resources?", "remediation":"Implement capacity monitoring and planning to prevent system overloads and failures." },
    { "id":34, "theme":"Technological",  "control":"A.8.7",  "weight":3, "text":"Are all systems protected against malware with up-to-date antivirus or endpoint protection?", "remediation":"Deploy and maintain endpoint protection software on all devices with automatic updates enabled." },
    { "id":35, "theme":"Technological",  "control":"A.8.8",  "weight":3, "text":"Do you have a process for identifying and managing technical vulnerabilities in your systems?", "remediation":"Implement a vulnerability management process including regular scanning and patching." },
    { "id":36, "theme":"Technological",  "control":"A.8.9",  "weight":2, "text":"Are system configurations managed and documented for all critical systems?", "remediation":"Document and baseline configurations for all critical systems and review them regularly." },
    { "id":37, "theme":"Technological",  "control":"A.8.10", "weight":2, "text":"Is information deleted securely when no longer required?", "remediation":"Implement secure deletion procedures for data that is no longer needed." },
    { "id":38, "theme":"Technological",  "control":"A.8.12", "weight":2, "text":"Do you have controls to prevent data leakage from your systems?", "remediation":"Implement data loss prevention controls to detect and prevent unauthorised data transfers." },
    { "id":39, "theme":"Technological",  "control":"A.8.13", "weight":3, "text":"Are regular backups of critical data performed and tested?", "remediation":"Implement automated daily backups with regular restoration testing to verify integrity." },
    { "id":40, "theme":"Technological",  "control":"A.8.15", "weight":2, "text":"Do you maintain activity logs for systems and applications?", "remediation":"Enable and retain audit logs for all critical systems and review them regularly." },
    { "id":41, "theme":"Technological",  "control":"A.8.16", "weight":2, "text":"Do you monitor networks and systems for anomalous activity?", "remediation":"Implement network and system monitoring tools to detect unusual or suspicious activity." },
    { "id":42, "theme":"Technological",  "control":"A.8.20", "weight":2, "text":"Are network security controls in place to protect your systems?", "remediation":"Implement firewalls, network segmentation, and access controls to protect network infrastructure." },
    { "id":43, "theme":"Technological",  "control":"A.8.24", "weight":3, "text":"Is encryption used to protect sensitive data at rest and in transit?", "remediation":"Implement encryption for sensitive data storage and use TLS for all data transmitted over networks." },
]